import React from 'react';
import { Button } from 'react-bootstrap';

function FilterSidebar({ categories = [], selectedCategory, setSelectedCategory, handleClearFilters }) {
    
    // Si no hay categorías, mostrar cargando (ya que se usa Mock Data, solo debe ocurrir en un error)
    if (categories.length === 0) {
        return (
            <div className="text-center text-gray-400 py-5">
                <i className="fas fa-spinner fa-spin mb-2"></i>
                <p className="text-sm">Cargando categorías...</p>
            </div>
        );
    }
    
    // Clases base reutilizables para todos los botones de categoría
    const baseButtonClasses = "w-full text-left px-3 py-2 rounded-lg transition-all duration-200 border-0 mb-1 d-flex align-items-center justify-content-between text-sm";
    
    return (
        <div className="d-flex flex-column gap-1">
            
            {/* Título de Categorías - Faltaba en tu vista para que se viera bien */}
            <h6 className="mb-2 font-bold text-slate-800">Categorías</h6> 

            {/* Botón para la opción 'Todas' */}
            <button
                onClick={() => setSelectedCategory('')}
                className={`${baseButtonClasses} 
                    ${selectedCategory === '' 
                        // Estilo ACTIVO: Fondo azul medianoche, texto blanco (Diseño final)
                        ? 'bg-[var(--brand-dark)] text-white font-bold shadow-md' 
                        // Estilo INACTIVO: Fondo transparente, texto gris
                        : 'bg-transparent text-gray-600 hover:bg-gray-100'
                    }`}
                aria-current={selectedCategory === '' ? 'page' : undefined}
            >
                <span>Todas</span>
                {selectedCategory === '' && <i className="fas fa-check text-xs"></i>}
            </button>

            {/* Mapeo de Categorías Reales */}
            {categories.map((category) => (
                <button
                    key={category.id || category.name}
                    onClick={() => setSelectedCategory(category.name)}
                    className={`${baseButtonClasses}
                        ${selectedCategory === category.name 
                            // Estilo ACTIVO
                            ? 'bg-[var(--brand-dark)] text-white font-bold shadow-md' 
                            // Estilo INACTIVO
                            : 'bg-transparent text-gray-600 hover:bg-gray-100'
                        }`}
                    aria-current={selectedCategory === category.name ? 'page' : undefined}
                >
                    <span>{category.name}</span>
                    {selectedCategory === category.name && <i className="fas fa-check text-xs"></i>}
                </button>
            ))}

            {/* Botón Limpiar Filtros */}
            {selectedCategory !== '' && (
                <Button 
                    variant="outline-danger" 
                    size="sm" 
                    className="w-full rounded-lg mt-3 d-flex align-items-center justify-content-center gap-2"
                    onClick={handleClearFilters}
                >
                    <i className="fas fa-times"></i> Limpiar Filtros
                </Button>
            )}
        </div>
    );
};

export default FilterSidebar;
